  `show_contact_details` tinyint(1) NOT NULL DEFAULT 1,
  `subject` json NULL,
  `teaching_method` enum('online','offline','both') CHARACTER SET utf8mb4 COLLATE utf8mb4_0900_ai_ci NOT NULL DEFAULT 'online',
  `qualification` varchar(50) CHARACTER SET utf8mb4 COLLATE utf8mb4_0900_ai_ci NOT NULL DEFAULT 'M.Sc in Math',
  `experience` int NOT NULL DEFAULT 2,
  `rating` float NOT NULL DEFAULT 4.3,
  `login_count` int NULL DEFAULT NULL,
  `is_verified` tinyint(1) NULL DEFAULT 0,
  PRIMARY KEY (`id`) USING BTREE,
  UNIQUE INDEX `username`(`username`) USING BTREE,
  UNIQUE INDEX `email`(`email`) USING BTREE
) ENGINE = InnoDB AUTO_INCREMENT = 1018 CHARACTER SET = utf8mb4 COLLATE = utf8mb4_0900_ai_ci ROW_FORMAT = DYNAMIC;

