CREATE TABLE `votes`  (
  `id` int NOT NULL AUTO_INCREMENT,
  `question_id` int NULL DEFAULT NULL,
  `answer_id` int NULL DEFAULT NULL,
  `user_id` int NOT NULL,
  `vote_type` enum('upvote','downvote','novote') CHARACTER SET utf8mb4 COLLATE utf8mb4_0900_ai_ci NOT NULL DEFAULT 'novote',
  `createdAt` datetime(0) NULL DEFAULT CURRENT_TIMESTAMP(0),
  `updatedAt` datetime(0) NULL DEFAULT CURRENT_TIMESTAMP(0),
  PRIMARY KEY (`id`) USING BTREE,
  INDEX `votes_ibfk_1`(`question_id`) USING BTREE,
  INDEX `votes_ibfk_2`(`answer_id`) USING BTREE,
  INDEX `votes_ibfk_3`(`user_id`) USING BTREE,
  CONSTRAINT `votes_ibfk_100` FOREIGN KEY (`question_id`) REFERENCES `questions` (`id`) ON DELETE SET NULL ON UPDATE CASCADE,
  CONSTRAINT `votes_ibfk_101` FOREIGN KEY (`answer_id`) REFERENCES `answers` (`id`) ON DELETE CASCADE ON UPDATE CASCADE,
  CONSTRAINT `votes_ibfk_102` FOREIGN KEY (`user_id`) REFERENCES `users` (`id`) ON DELETE CASCADE ON UPDATE CASCADE
) ENGINE = InnoDB AUTO_INCREMENT = 150 CHARACTER SET = utf8mb4 COLLATE = utf8mb4_0900_ai_ci ROW_FORMAT = DYNAMIC;

