INSERT INTO `answers` VALUES (59, NULL, '<p>React use a virtual DOM To efficiently update UI without re-render the entire page</p><p>which improve perfomance and make the application more responsive</p>', 457, 156, '2024-12-01 15:11:19', '2024-12-01 15:11:19', 1);
INSERT INTO `answers` VALUES (60, NULL, '<p><span style=\"background-color: rgb(31, 31, 31); color: rgb(238, 240, 255);\">&nbsp;</span>.doc, .docx, .dot,</p>', 621, 155, '2025-02-07 09:22:46', '2025-02-07 09:22:46', 0);
INSERT INTO `answers` VALUES (61, NULL, '<p>Hi,</p><p>Virtual DOM is a copy of real DOM. React JS uses 2 copies of the virtual DOM. When an update is made in the web application, </p><ol><li>React creates a virtual DOM with updated states, and </li><li>It compares this new virtual DOM version to the old virtual DOM (before the update), and</li><li>Based on the update, changes are made in the Real DOM</li></ol><p><br></p><p>With this process, updates are reflected faster (as compared to directly changing real DOM). </p>', 657, 156, '2025-03-31 11:26:02', '2025-03-31 11:26:02', 0);
INSERT INTO `answers` VALUES (62, NULL, '<p>JavaScript is a programming language used for adding interactivity to a web page. </p><p>HTML =&gt; adds structure to the page </p><p>CSS =&gt; makes the page look and feel good</p><p>JavaScript =&gt; add interactivity or functionality to the page</p><p>Ex: When you click a button and web page changes, or you submit a form, etc is happening because of javascript.</p>', 657, 150, '2025-03-31 11:32:14', '2025-03-31 11:32:14', 0);
INSERT INTO `answers` VALUES (63, NULL, '<p>In React version 19, updates are made to: -</p><ol><li>how errors are handled,</li><li>removed deprecated React APIs, </li><li>hooks are updated,</li><li>component rendering on server, etc</li></ol><p>Check this article for a better understanding: https://www.geeksforgeeks.org/react-19-new-features-and-updates/#1-server-components-a-major-update</p><p><br></p>', 657, 131, '2025-03-31 11:53:10', '2025-03-31 11:53:10', 0);
INSERT INTO `answers` VALUES (64, NULL, '<p>Follow below steps: -</p><ol><li>Add a unique \"id\" to each object in the default list, and pass it to your onClick function. Ex: onClick={() =&gt; yourFunction(id)}</li><li>Instead of slice, use filter method. ex: list.filter(val =&gt; val.id !== id)</li></ol>', 657, 90, '2025-03-31 12:00:06', '2025-03-31 12:00:06', 0);
