INSERT INTO `courses` VALUES (1, 'G20 Genius Certification Course', 'g20-genius-certificartion-course', 'The G20 Genius Certification Course is an advanced program designed for individuals seeking to expand their knowledge and skills in the fields of economics, finance, and international relations. This course covers the policies, initiatives, and strategies of the G20, the world\'s leading forum for international economic cooperation. Students will learn about the history and evolution of the G20, its role in global economic governance, and the major economic and political issues facing the group. Topics covered include trade, investment, financial regulation, climate change, and international development. The course also includes interactive discussions and case studies to provide a hands-on learning experience. Upon completion of the course, students will receive a G20 Genius Certification, recognizing their expertise in the field.  In addition to the core curriculum, this course also includes guest lectures and presentations by experts in the field, providing students with insights and perspectives from individuals actively involved in G20 policymaking and implementation. This will give students an opportunity to engage with real-world issues and understand the practical applications of the concepts they are learning in the classroom. The course also includes a culminating project where students will conduct original research on a topic related to the G20 and present their findings to the class. This will provide students with an opportunity to apply their knowledge and skills in a practical setting and develop valuable research and presentation skills.', 'active', 0, 'https://www.yuvamanthan.org/images/course.webp', 'yuvamanthan', '0', 0, 45, 0, 'http://localhost:3000/images/certificate.webp', NULL, '2023-01-23 16:46:46', '2023-01-23 16:46:47');
