INSERT INTO `educations` VALUES (79, 950, 'NEFT university ', 'graduate', 'Science ', '2022-08-10', '2025-08-15', 'My name is Dhruv, and I am writing to express my interest in the position of science teacher Teacher. I have recently completed my Bachelor\'s degree, and I bring with me over three years of teaching experience, during which I have taught Physics to students of classes 6th to 12th with a strong focus on conceptual clarity and exam-oriented preparation.\n\nI am deeply passionate about education and strive to make the subject engaging and understandable for all learners. Despite being a recent graduate, my practical experience in teaching has helped me develop effective classroom management skills and a student-centric approach.\n\nI would be honored to contribute to your institution\'s academic excellence. I am ready to take on responsibilities and grow further in a professional environment.\n\nThank you for considering my application. I look forward to the opportunity for an interview.', 'C+', '2025-10-05 03:35:31', '2025-10-05 03:35:31');
