INSERT INTO `institute_profiles` VALUES (24, 93, 432, NULL, 'I extend a warm welcome to the world of education and training at Our Institute. I represent Dav College, an institution that is committed to steering towards a radiant and knowledgeable future. As the founder of Ravi Sir, my primary objective is to ignite excellence and talent in education. Our training nurtures progress, empathy, and intellectual curiosity, all working together to shape well-rounded students. Our education is a blend of rich tradition and cutting-edge ideas. Our goal is to empower students not only in their studies but also in their social perspective. We create an environment where students can excel in their areas of interest.', 'Ajhai Khurd', 'Mathura', 'Uttar Pradesh', 'India', 281001, '2024-10-01', NULL, NULL, NULL, 'jaggi12345', 'N mohan chauraha', NULL, '', '', '', '', NULL, 'www.glacampus.com', NULL, '2024-10-05 05:45:48', '2024-10-05 05:45:48', NULL, 0, NULL);
