INSERT INTO `job_descriptions` VALUES (32, 1, 134, 'Vishal Eksathi', 'embdlabs@gmail.com', '8929000742', 'All Subjects teacher', '<p><strong>📢 Calling All Teachers Across Delhi NCR!</strong></p><p>We are collaborating with schools across multiple locations in Delhi NCR to bring you <strong>the best teaching opportunities</strong>.</p><p>If you’re a passionate educator looking for teaching jobs or career growth, <strong>Eksathi</strong> is the platform for you.</p><p>✅ <strong>Find jobs across reputed schools</strong></p><p> ✅ <strong>Apply directly – free of cost</strong></p><p> ✅ <strong>Connect with schools easily</strong></p><p>📍 <strong>Register now on Eksathi.com</strong></p><p> to explore current and upcoming openings!</p><p>Let Eksathi help you find the right teaching job in Delhi NCR.</p>', '[\"Online\", \"Part-Time\", \"Full-Time\", \"internship\", \"Guest Lecturer\"]', '{\"end_time\": \"14:00\", \"start_time\": \"07:00\"}', '6000', '[\"Maths\",\"Science\",\"English\",\"Hindi\"]', '{\"degree\":\"12Th\",\"subject\":\"All Subjects\",\"year\":\"\"}', '0-2 Years', 'Ghaziabad', 'Teacher', 100, 'Please apply for the jobs', NULL, '2025-09-22 00:00:00', '2025-09-20 05:31:07', '2025-12-31 00:00:00', 'expired', 'all-subjects-teacher1f8d0');
INSERT INTO `job_descriptions` VALUES (33, 2, 134, 'Vishal Eksathi', 'embdlabs@gmail.com', '0000000000', 'Maths Teacher in Delhi', '<p>Maths Teacher in Delhi</p>', '[\"Part-Time\", \"Online\", \"Full-Time\", \"internship\", \"Guest Lecturer\"]', '{\"end_time\": \"20:00\", \"start_time\": \"08:30\"}', '8000', '[\"maths\",\"physics\"]', '{\"degree\":\"B. Sc\",\"subject\":\"Maths\",\"year\":\"2024-01\"}', '0-2 Years', 'Delhi', 'Teacher', 10, 'Please apply for the jobs, will be forwarded to schools', NULL, '2025-09-22 00:00:00', '2025-09-21 15:05:10', '2025-12-31 00:00:00', 'expired', 'maths-teacher-in-delhi3945c');
INSERT INTO `job_descriptions` VALUES (34, 2, 134, 'Vishal Eksathi', 'embdlabs@gmail.com', '0000000000', 'Dance & Music Teacher', '<p>Dance &amp; Music Teacher required on part time and contract basis</p><p>Please upload your details, will be forwarded to the requester.</p><p><br></p><p>Job Locations</p><p>Delhi NCR launch (Ghaziabad, Noida, Delhi, Gurgaon, Faridabad, Greater Noida)</p>', '[\"Part-Time\", \"Online\", \"Full-Time\", \"internship\", \"Guest Lecturer\"]', '{\"end_time\": \"21:00\", \"start_time\": \"07:00\"}', '2000', '[\"Music\",\"Dance\",\"Classical\",\"Folk\"]', '{\"degree\":\"Diploma\",\"subject\":\"Music\",\"year\":\"2025-02\"}', '0-2 Years', 'Delhi NCR launch (Ghaziabad, Noida, Delhi, Gurgaon, Faridabad, Greater Noida)', 'Teacher', 10, 'Apply for the job, will be forwarded to requester', NULL, '2025-09-22 00:00:00', '2025-09-21 15:10:43', '2025-12-31 00:00:00', 'expired', 'dance-and-music-teacher945cc');
INSERT INTO `job_descriptions` VALUES (35, 1, 134, 'Vishal Eksathi', 'embdlabs@gmail.com', '0000000000', 'Yoga & Fitness Trainer', '<p>Yoga &amp; Fitness Trainer required on part time, full time and contract basis</p><p>Please upload your details, will be forwarded to the requester.</p><p><br></p><p>Job Locations</p><p>Delhi NCR launch (Ghaziabad, Noida, Delhi, Gurgaon, Faridabad, Greater Noida)</p>', '[\"Part-Time\", \"Online\", \"Full-Time\", \"internship\", \"Guest Lecturer\"]', '{\"end_time\": \"20:00\", \"start_time\": \"05:05\"}', '5000', '[\"Yoga\",\"Zumba\",\"Fitness\",\"Aerobics\",\"Gym\",\"Personal Trainer\"]', '{\"degree\":\"Diploma\",\"subject\":\"Yoga\",\"year\":\"2025-06\"}', '0-2 Years', 'Dance & Music Teacher required on part time and contract basis  Please upload your details, will be ', 'Teacher', 100, 'Apply for the job, will be forwarded to requester', NULL, '2025-09-22 00:00:00', '2025-09-21 15:17:30', '2025-12-31 00:00:00', 'expired', 'yoga-and-fitness-trainer45ccd');
INSERT INTO `job_descriptions` VALUES (36, 3, 136, 'Vishal Eksathi', 'embdlabs@gmail.com', '8929000742', 'Calling All AI & ML Professionals Across Delhi NCR!', '<p>We are collaborating with leading companies and institutes across multiple locations in Delhi NCR to bring you the best AI &amp; ML job opportunities.</p><p>If you’re a passionate AI/ML professional looking for career growth, <strong>Eksathi</strong> is the platform for you.</p><p>✅ Find AI &amp; ML jobs across reputed companies and institutes</p><p> ✅ Apply directly – free of cost</p><p> ✅ Connect with recruiters and organizations easily</p><p>📍 <strong>Register now on Eksathi.com</strong></p><p> to explore current and upcoming AI &amp; ML openings!</p><p>Let <strong>Eksathi</strong> help you find the right AI/ML career opportunity in Delhi NCR.</p>', '[\"Part-Time\", \"Online\", \"Full-Time\", \"internship\", \"Guest Lecturer\"]', '{\"end_time\": \"21:00\", \"start_time\": \"09:00\"}', '10000', '[\"AI\",\"ML\",\"LLM\",\"Deep Learning\",\"Python\"]', '{\"degree\":\"B. Tech\",\"subject\":\"Computer Science\",\"year\":\"2025-09\"}', '0-2 Years', 'Delhi', 'Teacher', 100, 'Apply for the job, will be forwarded to requester', NULL, '2025-09-24 00:00:00', '2025-09-24 16:37:16', '2025-12-31 00:00:00', 'expired', 'calling-all-ai-and-ml-professionals-across-delhi-ncr!f7198');
INSERT INTO `job_descriptions` VALUES (37, 2, 136, 'Vishal Eksathi', 'embdlabs@gmail.com', '8929000742', 'Science Teacher for All Classes', '<p>📢 <strong>Hiring Science Teachers – All Classes (Delhi NCR, India)</strong></p><p>Home Tutions, Tutors, TEaching opportunity.</p><p><br></p><p>Are you passionate about teaching and shaping young minds?</p><p> We are looking for <strong>dedicated Science Teachers</strong> to teach across different classes (Primary, Middle &amp; Senior) in reputed schools and institutes across <strong>Delhi NCR</strong>.</p><p>✅ Subjects: Physics, Chemistry, Biology, General Science</p><p> ✅ Levels: Primary, Middle, Senior Classes</p><p> ✅ Location: Multiple schools &amp; institutes in Delhi, Noida, Ghaziabad, Gurugram, Faridabad</p><p> ✅ Qualification: Graduate / Postgraduate in Science with B.Ed. (preferred)</p><p> ✅ Both freshers &amp; experienced teachers welcome</p><p>✨ Why join via <strong>Eksathi.com</strong>?</p><ul><li>Apply directly to multiple schools – <strong>Free of cost</strong></li><li>Explore job openings across Delhi NCR in one place</li><li>Build your profile &amp; connect with schools and students easily</li></ul><p>📍 <strong>Register now on Eksathi.com</strong></p><p> to apply for current and upcoming <strong>Science Teacher openings</strong>!</p>', '[\"Part-Time\", \"Online\", \"Full-Time\", \"internship\", \"Guest Lecturer\"]', '{\"end_time\": \"20:00\", \"start_time\": \"07:00\"}', '5000', '[\"Physics\",\"Chemistry\",\"Biology\",\"Science\",\"EVS\",\"Environmental Science\"]', '{\"degree\":\"12\",\"subject\":\"Science\",\"year\":\"2025-10\"}', '0-2 Years', 'Across India', 'Teacher', 100, 'Please update skills in details', NULL, '2025-10-05 00:00:00', '2025-10-04 18:45:31', '2025-12-31 00:00:00', 'expired', 'science-teacher-for-all-classes28aa9');
INSERT INTO `job_descriptions` VALUES (38, 5, 144, 'Prof. Ajmal Koya Pulikkal', 'recruitmentfaculty2025@nitmz.ac.in', '0000000000', 'Recruitment of Faculty Position', '<p>Advt. No. NITMZ/R-1-14/F/2025/1878    DAted : 14/10/2025</p><p><br></p><p>Applications are invited from indian nationals for faculty positions at NIT Mizoram.</p>', '[\"Full-Time\"]', '{\"end_time\": \"16:00\", \"start_time\": \"07:00\"}', '200000', '[\"All subjects\"]', '{\"degree\":\"MTech\",\"subject\":\"\",\"year\":\"\"}', '0-2 Years', 'NA', 'Teacher', 10, 'reach out for more details directly to college website\nwww.nitmz.ac.in', NULL, '2025-10-14 00:00:00', '2025-10-15 17:46:18', '2025-11-15 00:00:00', 'expired', 'recruitment-of-faculty-position83445');
INSERT INTO `job_descriptions` VALUES (39, 5, 146, 'Registrar', 'jmaukota22@gmail.com', '0000000000', 'Recruitment Notice for Teaching & Non Teaching Positions', '<p>Various Academic &amp; Administrative positions</p><p><br></p><ul><li>President (Vice Chancellor), Registrar</li><li>Professor</li><li>Support Staff</li></ul><p><br></p><p>Eligibility as per UGC/BCI/RCI/COA other statutory councils as applicable.</p><p><br></p><p><br></p><p><strong>Welcome to Eksathi.com! General Notice</strong></p><p> We share job updates collected from newspapers and public sources to help connect institutes and candidates. Please note that Eksathi.com only republishes available listings and is <strong>not responsible for the authenticity or outcome</strong> of any job post. We encourage all users to verify details before proceeding.</p><p><br></p>', '[\"Full-Time\", \"Part-Time\"]', '{\"end_time\": \"14:00\", \"start_time\": \"08:00\"}', 'NA', '[\"All support\",\"administrative\"]', '{\"degree\":\"NA\",\"subject\":\"\",\"year\":\"\"}', '0-2 Years', 'NA', 'Teacher', 100, 'www.jmau.ac.in\ncontact details : 0744-2774211', NULL, '2025-10-15 00:00:00', '2025-10-15 18:12:03', '2025-11-06 00:00:00', 'expired', 'recruitment-notice-for-teaching-and-non-teaching-positions34457');
