INSERT INTO `questions` VALUES (90, 'Removing object from array using hooks (useState)?', 'removing-object-from-array-using-hooks-(usestate)', '[{\"id\": 8, \"name\": \"HTML\"}, {\"id\": 9, \"name\": \"CSS\"}, {\"id\": 10, \"name\": \"Javascript\"}]', 5, '<p>I have an array of objects. I need to add a function to remove an object from my array without using the \"this\" keyword.</p><p><br></p><p>I tried using&nbsp;<code style=\"color: var(--black-800); background-color: var(--black-075);\">updateList(list.slice(list.indexOf(e.target.name, 1)))</code>. This removes everything but the last item in the array and I\'m not certain why.</p><pre class=\"ql-syntax\" spellcheck=\"false\">const defaultList = [\n{ name: \"ItemOne\" },\n{ name: \"ItemTwo\" },\n{ name: \"ItemThree\" }]\n\nconst [list, updateList] = useState(defaultList);\n\nconst handleRemoveItem = e =&gt; {\n    updateList(list.slice(list.indexOf(e.target.name, 1)))\n}\n\nreturn (\n    {list.map(item =&gt; {\n        return ( \n            &lt;&gt;\n            &lt;span onClick={handleRemoveItem}&gt;x &lt;/span&gt;\n            &lt;span&gt;{item.name}&lt;/span&gt;\n            &lt;/&gt;\n        )}\n    }\n)\n</pre><p>Expected behaviour: The clicked item will be removed from the list.</p><p>Actual behaviour: The entire list gets removed, minus the last item in the array.</p>', 0, NULL, NULL, NULL, NULL, 1, 0, NULL, '0000-00-00 00:00:00', '0000-00-00 00:00:00');
INSERT INTO `questions` VALUES (92, 'How to handle git gc fatal: bad object refs/remotes/origin/HEAD error?', 'how-to-handle-git-gc-fatal:-bad-object-refsremotesoriginhead-error', NULL, 7, '<p>I randomly hit this today while trying to run Git&nbsp;<em>garbage collect</em>:</p><pre class=\"ql-syntax\" spellcheck=\"false\">$ git gc\nfatal: bad object refs/remotes/origin/HEAD\nerror: failed to run repack\n</pre><p>How do I deal with this?</p>', 0, NULL, NULL, NULL, NULL, 1, 0, NULL, '0000-00-00 00:00:00', '0000-00-00 00:00:00');
