INSERT INTO `questions` VALUES (158, 'Agar ek ideal gas ko ek completely isolated system (no heat, no work exchange) mein daala gaya ho, jahan initial pressure P₁ aur volume V₁ hai, aur system ka temperature suddenly double ho jaye,  Toh final pressure aur volume kya hoga?', 'agar-ek-ideal-gas-ko-ek-completely-isolated-system-(no-heat-no-work-exchange)-mein-daala-gaya-ho-jahan-initial-pressure-p-aur-volume-v-hai-aur-system-ka-temperature-suddenly-double-ho-jaye-toh-final-pressure-aur-volume-kya-hoga79210', NULL, 17, '<h3>🧩 <strong>Given:</strong></h3><ul><li>A gas is placed in a <strong>completely isolated system</strong>.</li><li>Initial state:</li><li class=\"ql-indent-1\">Pressure = P1P_1P1​</li><li class=\"ql-indent-1\">Volume = V1V_1V1​</li><li class=\"ql-indent-1\">Temperature = T1T_1T1​</li><li>The system is <strong>thermally isolated</strong> → No heat in/out</li><li>The system is <strong>mechanically isolated</strong> → No work done</li><li>The question says:</li><li> 🔸 \"<strong>Temperature suddenly doubles</strong>\" → So T2=2T1T_2 = 2T_1T2​=2T1​</li></ul><p><br></p>', 0, NULL, NULL, NULL, NULL, 748, 0, NULL, '2025-06-19 11:21:27', '2025-06-19 11:21:27');
